  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (setup : StructuralExhaustion.Graph.TriangularShoulderCompletion.Setup base object baseline center)
  (site : StructuralExhaustion.Graph.TriangularShoulderCompletion.Site setup) {vertex : V},
  object.graph.Adj center (StructuralExhaustion.Graph.TriangularShoulderCompletion.shoulder setup site) →
    StructuralExhaustion.Graph.TriangularShoulderCompletion.IsCompletion setup site vertex → vertex = center

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (setup : StructuralExhaustion.Graph.TriangularShoulderCompletion.Setup base object baseline center)
  (site : StructuralExhaustion.Graph.TriangularShoulderCompletion.Site setup) {vertex : V},
  StructuralExhaustion.Graph.TriangularShoulderCompletion.IsCompletion setup site vertex →
    object.graph.Adj center vertex → vertex ≠ center → False

