  (targetCapability : StructuralExhaustion.CT14.Capability P)
  (source : StructuralExhaustion.CT5.ChargeLedgerResidual S sourceCapability input),
  ((StructuralExhaustion.Routes.CT5ToCT14.rule targetCapability).generate source ()).routeId =
    "CT5.residual.chargeLedger->CT14"

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V),
  StructuralExhaustion.CT14.multiplicity (StructuralExhaustion.Graph.FanClosedPortMass.capability profile)
      (StructuralExhaustion.Graph.FanClosedPortMass.context base object baseline) () =
    FinEnum.card { vertex // StructuralExhaustion.Graph.FanClosedPortMass.CubicClosedNeighbor profile vertex }

∀ {V : Type u_1} {object : StructuralExhaustion.Graph.FiniteObject V} {center : V}
  (profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V),
