∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  routing.Unsaturated → 0 ≤ ∑ vertex ∈ input.support, input.quarterCharge vertex

∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  -∑ vertex ∈ input.support, input.quarterCharge vertex ≤ ↑routing.totalOverload

∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  Nonempty routing.Saturated ∨ routing.Unsaturated

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.FiniteInducedBoundary.Profile object),
  ∀ vertex ∈ profile.remaining, 0 < profile.loss vertex → Nonempty profile.Incidence

