∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularFirstLanding.Setup base object baseline center}
  {port : StructuralExhaustion.Graph.TriangularFirstLanding.TriPort setup}
  {root :
    StructuralExhaustion.Graph.DartReturn object.graph
      (StructuralExhaustion.Graph.TriangularPortReturn.rootDart setup port)}
  {avoids : ¬StructuralExhaustion.Graph.HasCycleWithLength object.graph base.LengthOK},
  StructuralExhaustion.Graph.TriangularPortReturn.VerifiedStage setup port root avoids →
    StructuralExhaustion.Graph.TriangularFirstLanding.VerifiedStage setup →
      StructuralExhaustion.Graph.TriangularFirstLanding.ClassifiedReturnAlternative
        (StructuralExhaustion.Graph.TriangularPortReturn.certificate setup port root)

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  first ≠ second →
    ¬object.graph.Adj (StructuralExhaustion.Graph.HighCenterPort.endpoint object center ↑first)
        (StructuralExhaustion.Graph.HighCenterPort.endpoint object center ↑second)

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  first ≠ second →
    ∀ (left right : Bool),
      StructuralExhaustion.Graph.TriangularCrossShoulder.shoulder first left ≠
        StructuralExhaustion.Graph.TriangularCrossShoulder.shoulder second right

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  first ≠ second →
    ∀ (edge₁ edge₂ : StructuralExhaustion.Graph.TriangularCrossShoulder.CrossEdge first second),
      edge₁ ≠ edge₂ → StructuralExhaustion.Graph.TriangularCrossShoulder.HighShoulder first second

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  first ≠ second →
    StructuralExhaustion.Graph.TriangularCrossShoulder.HighShoulder first second ∨
      StructuralExhaustion.CT9.fibreCount (StructuralExhaustion.Graph.TriangularCrossShoulder.capability first second)
          (StructuralExhaustion.Graph.TriangularCrossShoulder.input first second) () ≤
        1

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  first ≠ second →
    ((∀ (side : Bool), object.degree (StructuralExhaustion.Graph.TriangularCrossShoulder.shoulder first side) = 3) ∧
        ∀ (side : Bool), object.degree (StructuralExhaustion.Graph.TriangularCrossShoulder.shoulder second side) = 3) →
      StructuralExhaustion.CT9.BoundedRun (StructuralExhaustion.Graph.TriangularCrossShoulder.capability first second)
        (StructuralExhaustion.Graph.TriangularCrossShoulder.input first second)

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup),
  StructuralExhaustion.Graph.TriangularCrossShoulder.checks first second ≤ 5

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  {setup : StructuralExhaustion.Graph.TriangularCrossShoulder.Setup base object baseline center}
  (first second : StructuralExhaustion.Graph.TriangularCrossShoulder.TriPort setup) (portsNe : first ≠ second),
  StructuralExhaustion.Graph.TriangularCrossShoulder.VerifiedStage first second portsNe

∀ {P : StructuralExhaustion.Core.Problem} {S : StructuralExhaustion.CT5.Spec P}
  {sourceCapability : StructuralExhaustion.CT5.Capability S} {input : StructuralExhaustion.CT5.Input P}
  (targetCapability : StructuralExhaustion.CT14.Capability P)
  (source : StructuralExhaustion.CT5.ChargeLedgerResidual S sourceCapability input),
  ((StructuralExhaustion.Routes.CT5ToCT14.rule targetCapability).generate source ()).routeId =
    "CT5.residual.chargeLedger->CT14"

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V),
  StructuralExhaustion.CT14.multiplicity (StructuralExhaustion.Graph.FanClosedPortMass.capability profile)
      (StructuralExhaustion.Graph.FanClosedPortMass.context base object baseline) () =
    FinEnum.card { vertex // StructuralExhaustion.Graph.FanClosedPortMass.CubicClosedNeighbor profile vertex }

∀ {V : Type u_1} {object : StructuralExhaustion.Graph.FiniteObject V} {center : V}
  (profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V),
  FinEnum.card (StructuralExhaustion.Graph.HybridFanIncidence.Incidence profile) ≤ 2 * FinEnum.card V

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V),
  object.degree center ≤ 8 →
    StructuralExhaustion.Graph.HybridFanIncidence.remainingNonWindowDemand profile ≤
      ↑(StructuralExhaustion.Graph.HybridFanIncidence.nonWindowQuarterCredit profile)

∀ (ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget)
  {firstOrder secondOrder : ℕ} {firstPath : SimpleGraph.pathGraph firstOrder ↪g ctx.G.object.graph}
  {secondPath : SimpleGraph.pathGraph secondOrder ↪g ctx.G.object.graph}
  (data : StructuralExhaustion.Graph.TwoWindowCycle.Data firstPath secondPath),
  StructuralExhaustion.Graph.TwoWindowCycle.DirectCycleFree Internal.PowerOfTwoLength data

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  (marked : Internal.CertificateClosedMarkedFan ctx),
  0 ≤ marked.chargeProfile.neighborhoodQuarterChargeLower ctx.toBranchContext

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  (entry : Internal.PositiveDeficitMarkedFan ctx),
  Internal.FanClosedMassStage ctx entry.fan.center ⋯ entry.Assigned entry.assignedDecidable entry.first entry.second ⋯ ⋯

∀ {V : Type u_1} {base : StructuralExhaustion.Graph.MinimumDegreeCycle.StaticInput V fun x => Unit}
  {object : StructuralExhaustion.Graph.FiniteObject V} {baseline : base.problem.Baseline object} {center : V}
  (centerHigh : 4 ≤ object.degree center)
  (deletionCritical : ∀ (dart : object.graph.Dart), object.degree dart.toProd.1 = 3 ∨ object.degree dart.toProd.2 = 3)
  {profile : StructuralExhaustion.Graph.FanClosedPort.FanWindowProfile V}
  {first second : StructuralExhaustion.Graph.FanClosedPort.OpenPort centerHigh deletionCritical}
  {pair : StructuralExhaustion.Graph.FanClosedPort.CompatiblePair centerHigh deletionCritical first second}
  {assigned : StructuralExhaustion.Graph.FanClosedPort.AssignedPair centerHigh deletionCritical profile first second}
  {fourFree :
    ¬StructuralExhaustion.Graph.HasCycleWithLength object.graph
        StructuralExhaustion.Graph.HighCenterStructure.FourLength}
  {degreeLeEight : object.degree center ≤ 8},
  StructuralExhaustion.Graph.HybridFanIncidence.VerifiedStage centerHigh deletionCritical profile first second pair
      assigned fourFree degreeLeEight →
    StructuralExhaustion.Graph.HybridFanIncidence.LocalLedgerEntry centerHigh deletionCritical profile first second
      assigned

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  (support : Internal.TypeBAssignedSupport ctx) (demand : support.Demand),
  ↑demand ∈ support.ledgerProfile.demandSupport demand

∀ {Demand : Type uDemand} {Carrier : Type uCarrier}
  (profile : StructuralExhaustion.Core.FiniteRefinedLedger.Profile Demand Carrier),
  Nonempty profile.FullChoice ∨ profile.FullObstruction

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  (support : Internal.TypeBAssignedSupport ctx),
  (support.completionProfile.run ctx.toBranchContext).iterations ≤ FinEnum.card ctx.G.Vertex

∀ {Item : Type uItem} {Carrier : Type uCarrier}
  (profile : StructuralExhaustion.Core.FiniteWeightedSelection.Profile Item Carrier) (candidate : profile.Candidate),
  profile.carrierSupport candidate ⊆ profile.declaredCarrierSupport

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  {support : Internal.TypeBAssignedSupport ctx} (obstruction : support.MinimalOverlap) {demand : support.Demand},
  demand ∈ obstruction.selected → ↑demand ∈ obstruction.carrierSet

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  {support : Internal.TypeBAssignedSupport ctx} (demand : support.Demand) {neighbor : ctx.G.Vertex},
  ctx.G.object.graph.Adj (↑demand) neighbor → ctx.G.object.degree neighbor = 3

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  {order : ℕ} {path : SimpleGraph.pathGraph order ↪g ctx.G.object.graph}
  (pair : StructuralExhaustion.Graph.FanWindowCycle.ClosedPair path),
  StructuralExhaustion.Graph.FanWindowCycle.DirectCycleFree Internal.PowerOfTwoLength pair

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  {firstOrder secondOrder : ℕ} {firstPath : SimpleGraph.pathGraph firstOrder ↪g ctx.G.object.graph}
  {secondPath : SimpleGraph.pathGraph secondOrder ↪g ctx.G.object.graph}
  (data : StructuralExhaustion.Graph.TwoWindowCycle.Data firstPath secondPath),
  StructuralExhaustion.Graph.TwoWindowCycle.DirectCycleFree Internal.PowerOfTwoLength data

∀ {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext Internal.PackedProblem Internal.PackedTarget}
  {T : Type u} (boundaries : FinEnum T) [inst : Nonempty T] (atom : Internal.ConcreteCT3.ProperAtom ctx boundaries)
  (compression : Internal.ConcreteCT3.Compression atom), False

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.AssignedSupportCharge.Profile object),
  0 ≤ ∑ center ∈ profile.assignedCenters, profile.coreQuarterChargeAt center + ↑profile.assignedCenters.card

∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  routing.Unsaturated → 0 ≤ ∑ vertex ∈ input.support, input.quarterCharge vertex

∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  -∑ vertex ∈ input.support, input.quarterCharge vertex ≤ ↑routing.totalOverload

∀ {Vertex : Type u} {input : StructuralExhaustion.Core.FiniteReceiverDischarge.Input Vertex}
  (routing : StructuralExhaustion.Core.FiniteReceiverDischarge.Routing input),
  Nonempty routing.Saturated ∨ routing.Unsaturated

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.FiniteInducedBoundary.Profile object),
  ∀ vertex ∈ profile.remaining, 0 < profile.loss vertex → Nonempty profile.Incidence

